class Solution:
    def countKeyChanges(self, s):
        count = 0
        for i in range(1, len(s)):
            if s[i].lower() != s[i - 1].lower():
                count += 1
        return count

solutions.python:
class Solution:
    def countKeyChanges(self, s):
        t = s.lower()
        return sum(1 for i in range(1, len(t)) if t[i] != t[i - 1])

